 2→  "name": "browser-comp",
 3→  "version": "1.0.0",
 4→  "description": "Browser compatibility screenshot comparison tool",
 5→  "type": "module",
 6→  "main": "capture.mjs",
 7→  "bin": {
 8→    "browser-comp": "./capture.mjs"
 9→  },
10→  "scripts": {
11→    "capture": "node capture.mjs"
12→  },
