  1→#!/usr/bin/env node
  2→
  3→/**
  4→ * Browser Compatibility Screenshot Comparison Tool
  5→ *
  6→ * Captures screenshots of a target URL across multiple browser engines
  7→ * and device emulations using Playwright, then generates an HTML comparison report.
  8→ *
  9→ * Usage:
 10→ *   node capture.mjs <url> [options]
 11→ *
 12→ * Options:
 13→ *   --output, -o    Output directory (default: ./report)
 14→ *   --width, -w     Custom viewport width
 15→ *   --height, -h    Custom viewport height
 16→ *   --full-page     Capture full page screenshots (default: true)
 17→ *   --delay         Wait ms after page load before capture (default: 2000)
 18→ *   --devices       Comma-separated device list (default: all presets)
 19→ *   --browsers      Comma-separated browser list: chromium,webkit,firefox (default: all)
 20→ *   --inject-eruda  Inject Eruda console for debugging
 21→ *   --ua-spoof      Spoof in-app browser user agents (facebook, instagram, tiktok, etc.)
 22→ *
 23→ * Examples:
 24→ *   node capture.mjs https://example.com
 25→ *   node capture.mjs https://example.com --browsers chromium,webkit --devices "iPhone 15,Pixel 7"
 26→ *   node capture.mjs https://example.com --ua-spoof facebook,instagram,wechat
 27→ */
 28→
 29→import path from 'path';
 30→import fs from 'fs/promises';
 31→import { fileURLToPath } from 'url';
 32→import { DEFAULT_DEVICES } from './lib/browsers.mjs';
 33→import { captureScreenshots } from './lib/capture-engine.mjs';
 34→import { generateReport } from './lib/report-generator.mjs';
 35→
 36→const __dirname = path.dirname(fileURLToPath(import.meta.url));
 37→
 38→// ============================================================
 39→// Defaults
 40→// ============================================================
 41→const DEFAULTS = {
 42→  url: null,
 43→  output: './report',
 44→  fullPage: true,
 45→  delay: 2000,
 46→  devices: DEFAULT_DEVICES,
 47→  browsers: ['chromium', 'webkit', 'firefox'],
 48→  uaSpoof: [],
 49→  injectEruda: false,
 50→  customWidth: null,
 51→  customHeight: null,
 52→};
 53→
 54→// ============================================================
 55→// Parse CLI Arguments
 56→// ============================================================
 57→function parseArgs(args) {
 58→  const parsed = {};
 59→
 60→  let i = 0;
 61→  while (i < args.length) {
 62→    const arg = args[i];
 63→    if (arg === '--output' || arg === '-o') {
 64→      parsed.output = args[++i];
 65→    } else if (arg === '--width' || arg === '-w') {
 66→      parsed.customWidth = parseInt(args[++i]);
 67→    } else if (arg === '--height' || arg === '-h') {
 68→      parsed.customHeight = parseInt(args[++i]);
 69→    } else if (arg === '--full-page') {
 70→      parsed.fullPage = args[++i] !== 'false';
 71→    } else if (arg === '--delay') {
 72→      parsed.delay = parseInt(args[++i]);
 73→    } else if (arg === '--devices') {
 74→      parsed.devices = args[++i].split(',').map(d => d.trim());
 75→    } else if (arg === '--browsers') {
 76→      parsed.browsers = args[++i].split(',').map(b => b.trim().toLowerCase());
 77→    } else if (arg === '--ua-spoof') {
 78→      parsed.uaSpoof = args[++i].split(',').map(u => u.trim().toLowerCase());
 79→    } else if (arg === '--inject-eruda') {
 80→      parsed.injectEruda = true;
 81→    } else if (!arg.startsWith('-')) {
 82→      parsed.url = arg;
 83→    }
 84→    i++;
 85→  }
 86→
 87→  return parsed;
 88→}
 89→
 90→// ============================================================
 91→// Load .browsercompare.json config
 92→// ============================================================
 93→async function loadConfigFile() {
 94→  const configPath = path.resolve(process.cwd(), '.browsercompare.json');
 95→  try {
 96→    const raw = await fs.readFile(configPath, 'utf-8');
 97→    const config = JSON.parse(raw);
 98→    console.log(`\uD83D\uDCC4 Loaded config from ${configPath}`);
 99→    return config;
100→  } catch {
101→    return {};
102→  }
103→}
104→
105→// ============================================================
106→// Main
107→// ============================================================
108→const fileConfig = await loadConfigFile();
109→const cliArgs = parseArgs(process.argv.slice(2));
110→
111→// Merge order: defaults < config file < CLI args
112→const config = { ...DEFAULTS, ...fileConfig, ...cliArgs };
113→
114→const results = await captureScreenshots(config);
115→await generateReport(results, config, __dirname);
116→

  1→/**
  2→ * Report HTML generation
  3→ */
  4→
  5→import fs from 'fs/promises';
  6→import path from 'path';
  7→
  8→/**
  9→ * Generate an HTML comparison report from capture results.
 10→ * @param {Array} results - Screenshot capture results
 11→ * @param {Object} config - Capture configuration
 12→ * @param {string} templateDir - Directory containing report-template.html
 13→ */
 14→export async function generateReport(results, config, templateDir) {
 15→  const outputDir = path.resolve(config.output);
 16→
 17→  const metadata = {
 18→    url: config.url,
 19→    capturedAt: new Date().toISOString(),
 20→    results: results.map(r => ({
 21→      ...r,
 22→      filepath: undefined,
 23→    })),
 24→  };
 25→
 26→  await fs.writeFile(
 27→    path.join(outputDir, 'metadata.json'),
 28→    JSON.stringify(metadata, null, 2)
 29→  );
 30→
 31→  const templatePath = path.join(templateDir, 'report-template.html');
 32→  let template;
 33→  try {
 34→    template = await fs.readFile(templatePath, 'utf-8');
 35→  } catch {
 36→    template = generateDefaultTemplate();
 37→  }
 38→
 39→  const html = template
 40→    .replace('__METADATA__', JSON.stringify(metadata))
 41→    .replace('__URL__', config.url)
 42→    .replace('__DATE__', new Date().toLocaleString());
 43→
 44→  await fs.writeFile(path.join(outputDir, 'index.html'), html);
 45→
 46→  console.log(`\n\u2705 Report generated: ${path.join(outputDir, 'index.html')}`);
 47→  console.log(`\uD83D\uDCF8 ${results.length} screenshots captured`);
 48→
 49→  return path.join(outputDir, 'index.html');
 50→}
 51→
 52→function generateDefaultTemplate() {
 53→  return `<!DOCTYPE html>
 54→<html lang="en">
 55→<head>
 56→<meta charset="UTF-8">
 57→<meta name="viewport" content="width=device-width, initial-scale=1.0">
 58→<title>Browser Comparison Report</title>
 59→<style>
 60→  * { margin: 0; padding: 0; box-sizing: border-box; }
 61→  body { font-family: -apple-system, system-ui, sans-serif; background: #0a0a0a; color: #e0e0e0; padding: 2rem; }
 62→  h1 { font-size: 1.5rem; margin-bottom: 1rem; }
 63→  .grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(350px, 1fr)); gap: 1.5rem; }
 64→  .card { background: #1a1a1a; border-radius: 12px; overflow: hidden; border: 1px solid #333; }
 65→  .card-header { padding: 1rem; border-bottom: 1px solid #333; }
 66→  .card-header h3 { font-size: 0.9rem; }
 67→  .card-header p { font-size: 0.75rem; color: #888; margin-top: 0.25rem; }
 68→  .card img { width: 100%; display: block; }
 69→  .tag { display: inline-block; padding: 2px 8px; border-radius: 4px; font-size: 0.7rem; font-weight: 600; }
 70→  .tag-chromium { background: #1a3a1a; color: #4caf50; }
 71→  .tag-webkit { background: #1a1a3a; color: #5c8aff; }
 72→  .tag-firefox { background: #3a2a1a; color: #ff9800; }
 73→  .tag-inapp { background: #3a1a2a; color: #e91e63; }
 74→  .tag-ios { background: #1a1a2a; color: #79c0ff; }
 75→  .tag-android { background: #1a2a1a; color: #7ee787; }
 76→  .tag-desktop { background: #2a1a3a; color: #ab82ff; }
 77→</style>
 78→</head>
 79→<body>
 80→<h1>Browser Comparison \u2014 __URL__</h1>
 81→<p style="color:#888;margin-bottom:2rem;">Captured: __DATE__</p>
 82→<div class="grid" id="grid"></div>
 83→<script>
 84→const meta = __METADATA__;
 85→const grid = document.getElementById('grid');
 86→meta.results.forEach(r => {
 87→  const tagClass = r.type === 'in-app' ? 'tag-inapp' : 'tag-' + r.browserEngine;
 88→  const platformTag = r.platform || 'android';
 89→  grid.innerHTML += \`
 90→    <div class="card">
 91→      <div class="card-header">
 92→        <h3>\${r.browser} <span class="tag \${tagClass}">\${r.browserEngine}</span> <span class="tag tag-\${platformTag}">\${platformTag}</span></h3>
 93→        <p>\${r.device} \u2014 \${r.viewport.width}\xD7\${r.viewport.height}</p>
 94→      </div>
 95→      <img src="screenshots/\${r.filename}" alt="\${r.browser} \${r.device}" loading="lazy">
 96→    </div>
 97→  \`;
 98→});
 99→</script>
100→</body>
101→</html>`;
102→}
