367→<body>
368→
369→<div class="header">
370→  <div class="header-top">
371→    <div class="header-icon">🔍</div>
372→    <h1>Browser Compatibility Report</h1>
373→  </div>
374→  <div class="header-meta">
375→    <div class="header-meta-item">
376→      URL: <code id="target-url">__URL__</code>
377→    </div>
378→    <div class="header-meta-item">
379→      Captured: <code id="capture-date">__DATE__</code>
380→    </div>
381→    <div class="header-meta-item">
382→      Screenshots: <code id="total-count">0</code>
383→    </div>
384→  </div>
385→</div>
386→
387→<div class="toolbar">
388→  <div class="toolbar-group" id="engine-filters">
389→    <button class="filter-btn active" data-filter="all">All</button>
390→    <button class="filter-btn" data-filter="chromium">Chromium</button>
391→    <button class="filter-btn" data-filter="webkit">WebKit</button>
392→    <button class="filter-btn" data-filter="firefox">Firefox</button>
393→    <button class="filter-btn" data-filter="in-app">In-App</button>
394→  </div>
395→  <div class="toolbar-separator"></div>
396→  <div class="toolbar-group" id="platform-filters">
397→    <button class="filter-btn active" data-platform="all">All Devices</button>
398→    <button class="filter-btn" data-platform="ios">iOS</button>
399→    <button class="filter-btn" data-platform="android">Android</button>
400→    <button class="filter-btn" data-platform="desktop">Computer</button>
401→  </div>
402→  <div class="toolbar-separator"></div>
403→  <div class="view-toggle">
404→    <button class="filter-btn active" data-view="grid">Grid</button>
405→    <button class="filter-btn" data-view="side-by-side">Side-by-Side</button>
406→    <button class="filter-btn" data-view="diff">Compare 2</button>
407→  </div>
408→</div>
409→
410→<div class="content">
411→  <div class="stats" id="stats"></div>
412→  <div id="cards-container" class="grid-view"></div>
413→</div>
414→
415→<!-- Lightbox -->
416→<div class="lightbox" id="lightbox">
417→  <img id="lightbox-img" src="" alt="">
418→  <div class="lightbox-label" id="lightbox-label"></div>
419→</div>
420→
421→<script>
422→// ============================================================
423→// Data & State
424→// ============================================================
425→const metadata = __METADATA__;
426→let currentFilter = 'all';
427→let currentPlatform = 'all';
428→let currentView = 'grid';
429→let diffSelections = [];
430→
431→document.getElementById('total-count').textContent = metadata.results.length;
432→
433→// ============================================================
434→// Render
435→// ============================================================
436→function getFilteredResults() {
437→  return metadata.results.filter(r => {
438→    const engineMatch = currentFilter === 'all'
439→      || (currentFilter === 'in-app' && r.type === 'in-app')
440→      || (r.browserEngine === currentFilter && r.type !== 'in-app');
441→    const platformMatch = currentPlatform === 'all'
442→      || r.platform === currentPlatform;
443→    return engineMatch && platformMatch;
444→  });
445→}
446→
447→function renderStats() {
448→  const results = metadata.results;
449→  const engines = [...new Set(results.map(r => r.browserEngine))];
450→  const devices = [...new Set(results.map(r => r.device))];
451→  const inAppCount = results.filter(r => r.type === 'in-app').length;
452→
453→  document.getElementById('stats').innerHTML = `
454→    <div class="stat-chip">
455→      <span class="stat-number">${results.length}</span>
456→      <span class="stat-label">Total<br>Screenshots</span>
457→    </div>
458→    <div class="stat-chip">
459→      <span class="stat-number">${engines.length}</span>
460→      <span class="stat-label">Browser<br>Engines</span>
461→    </div>
462→    <div class="stat-chip">
463→      <span class="stat-number">${devices.length}</span>
464→      <span class="stat-label">Device<br>Profiles</span>
465→    </div>
466→    <div class="stat-chip">
467→      <span class="stat-number">${inAppCount}</span>
468→      <span class="stat-label">In-App<br>Browsers</span>
469→    </div>
470→  `;
471→}
472→
473→function createCard(result, index) {
474→  const engineTag = result.type === 'in-app' ? 'inapp' : result.browserEngine;
475→  const platformTag = result.platform;
476→  const isDiffMode = currentView === 'diff';
477→  const isSelected = diffSelections.includes(index);
478→
479→  return `
480→    <div class="card ${isSelected ? 'diff-selected' : ''}"
481→         data-index="${index}"
482→         ${isDiffMode ? `onclick="toggleDiffSelect(${index})"` : ''}>
483→      <div class="card-header">
484→        <div>
485→          <div class="card-title">${result.browser}</div>
486→          <div class="card-subtitle">${result.device}</div>
487→        </div>
488→        <div class="card-tags">
489→          <span class="tag tag-${engineTag}">${result.browserEngine}</span>
490→          <span class="tag tag-${platformTag}">${platformTag}</span>
491→        </div>
492→      </div>
493→      <div class="card-image-container" ${!isDiffMode ? `onclick="openLightbox('screenshots/${result.filename}', '${result.browser} — ${result.device}')"` : ''}>
494→        <img src="screenshots/${result.filename}" alt="${result.browser} ${result.device}" loading="lazy">
495→      </div>
496→      <div class="card-footer">
497→        <span>${result.viewport.width} × ${result.viewport.height}</span>
498→        <span>${result.type === 'in-app' ? '📲 In-App WebView' : '🌐 Native Browser'}</span>
499→      </div>
500→    </div>
501→  `;
502→}
503→
504→function render() {
505→  const container = document.getElementById('cards-container');
506→  const filtered = getFilteredResults();
507→
508→  container.className = currentView === 'side-by-side' ? 'side-by-side-view'
509→    : currentView === 'diff' ? 'diff-view'
510→    : 'grid-view';
511→
512→  if (filtered.length === 0) {
513→    container.innerHTML = `
514→      <div class="empty" style="grid-column: 1/-1;">
515→        <div class="empty-icon">🔍</div>
516→        <p>No screenshots match your filters</p>
517→      </div>`;
518→    return;
519→  }
520→
521→  container.innerHTML = filtered.map((r, i) => createCard(r, metadata.results.indexOf(r))).join('');
522→}
523→
524→// ============================================================
525→// Filters
526→// ============================================================
527→document.getElementById('engine-filters').addEventListener('click', e => {
528→  if (!e.target.matches('.filter-btn')) return;
529→  document.querySelectorAll('#engine-filters .filter-btn').forEach(b => b.classList.remove('active', 'active-chromium', 'active-webkit', 'active-firefox', 'active-inapp'));
530→  const filter = e.target.dataset.filter;
531→  currentFilter = filter;
532→  e.target.classList.add('active');
533→  if (filter !== 'all') e.target.classList.add('active-' + (filter === 'in-app' ? 'inapp' : filter));
534→  render();
535→});
536→
537→document.getElementById('platform-filters').addEventListener('click', e => {
538→  if (!e.target.matches('.filter-btn')) return;
539→  document.querySelectorAll('#platform-filters .filter-btn').forEach(b => b.classList.remove('active'));
540→  currentPlatform = e.target.dataset.platform;
541→  e.target.classList.add('active');
542→  render();
543→});
544→
545→document.querySelector('.view-toggle').addEventListener('click', e => {
546→  if (!e.target.matches('.filter-btn')) return;
547→  document.querySelectorAll('.view-toggle .filter-btn').forEach(b => b.classList.remove('active'));
548→  currentView = e.target.dataset.view;
549→  e.target.classList.add('active');
550→  diffSelections = [];
551→  render();
552→});
553→
554→// ============================================================
555→// Diff Mode
556→// ============================================================
557→function toggleDiffSelect(index) {
558→  const pos = diffSelections.indexOf(index);
559→  if (pos >= 0) {
560→    diffSelections.splice(pos, 1);
561→  } else if (diffSelections.length < 2) {
562→    diffSelections.push(index);
563→  }
564→  render();
565→}
566→
567→// ============================================================
568→// Lightbox
569→// ============================================================
570→function openLightbox(src, label) {
571→  const lb = document.getElementById('lightbox');
572→  document.getElementById('lightbox-img').src = src;
573→  document.getElementById('lightbox-label').textContent = label;
574→  lb.classList.add('active');
575→}
576→
577→document.getElementById('lightbox').addEventListener('click', () => {
578→  document.getElementById('lightbox').classList.remove('active');
579→});
580→
581→document.addEventListener('keydown', e => {
582→  if (e.key === 'Escape') document.getElementById('lightbox').classList.remove('active');
583→});
584→
585→// ============================================================
586→// Init
587→// ============================================================
588→renderStats();
589→render();
590→</script>
591→</body>
592→</html>
593→

