#!/usr/bin/env node
import path from 'path';
import fs from 'fs/promises';
import { fileURLToPath } from 'url';
import { DEFAULT_DEVICES } from './lib/browsers.mjs';
import { captureScreenshots } from './lib/capture-engine.mjs';
import { generateReport } from './lib/report-generator.mjs';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

const DEFAULTS = {
  url: null, output: './report', fullPage: true, delay: 2000,
  devices: DEFAULT_DEVICES, browsers: ['chromium', 'webkit', 'firefox'],
  uaSpoof: [], injectEruda: false, customWidth: null, customHeight: null,
};

function parseArgs(args) {
  const parsed = {};
  let i = 0;
  while (i < args.length) {
    const arg = args[i];
    if (arg === '--output' || arg === '-o') { parsed.output = args[++i]; }
    else if (arg === '--width' || arg === '-w') { parsed.customWidth = parseInt(args[++i]); }
    else if (arg === '--height' || arg === '-h') { parsed.customHeight = parseInt(args[++i]); }
    else if (arg === '--full-page') { parsed.fullPage = args[++i] !== 'false'; }
    else if (arg === '--delay') { parsed.delay = parseInt(args[++i]); }
    else if (arg === '--devices') { parsed.devices = args[++i].split(',').map(d => d.trim()); }
    else if (arg === '--browsers') { parsed.browsers = args[++i].split(',').map(b => b.trim().toLowerCase()); }
    else if (arg === '--ua-spoof') { parsed.uaSpoof = args[++i].split(',').map(u => u.trim().toLowerCase()); }
    else if (arg === '--inject-eruda') { parsed.injectEruda = true; }
    else if (!arg.startsWith('-')) { parsed.url = arg; }
    i++;
  }
  return parsed;
}

async function loadConfigFile() {
  const configPath = path.resolve(process.cwd(), '.browsercompare.json');
  try {
    const raw = await fs.readFile(configPath, 'utf-8');
    const config = JSON.parse(raw);
    console.log(`📄 Loaded config from ${configPath}`);
    return config;
  } catch { return {}; }
}

const fileConfig = await loadConfigFile();
const cliArgs = parseArgs(process.argv.slice(2));
const config = { ...DEFAULTS, ...fileConfig, ...cliArgs };
const results = await captureScreenshots(config);
await generateReport(results, config, __dirname);
