    url: config.url,
    capturedAt: new Date().toISOString(),
    results: results.map(r => ({ ...r, filepath: undefined })),
  };

  await fs.writeFile(path.join(outputDir, 'metadata.json'), JSON.stringify(metadata, null, 2));

  const templatePath = path.join(templateDir, 'report-template.html');
  let template;
  try {
    template = await fs.readFile(templatePath, 'utf-8');
  } catch {
    template = generateDefaultTemplate();
  }

  const html = template
    .replace('__METADATA__', JSON.stringify(metadata))
    .replace('__URL__', config.url)
    .replace('__DATE__', new Date().toLocaleString());

  await fs.writeFile(path.join(outputDir, 'index.html'), html);
  console.log(`✅ Report generated: ${path.join(outputDir, 'index.html')}`);
