import { devices } from 'playwright';
import path from 'path';
import fs from 'fs/promises';
import { IN_APP_UA_STRINGS, BROWSER_LAUNCHERS, getPlatform } from './browsers.mjs';

const MAX_RETRIES = 3;
const BASE_DELAY_MS = 1000;

async function captureWithRetry(fn, label) {
  for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
    try {
      const result = await fn();
      return { success: true, ...result };
    } catch (err) {
      const isLastAttempt = attempt === MAX_RETRIES;
      if (isLastAttempt) {
        console.error(`❌ ${label} — failed after ${MAX_RETRIES} attempts: ${err.message}`);
        return { success: false, error: err.message };
      }
      const backoff = BASE_DELAY_MS * Math.pow(2, attempt - 1);
      console.warn(`⚠️  ${label} — attempt ${attempt}/${MAX_RETRIES} failed: ${err.message}. Retrying in ${backoff}ms...`);
      await new Promise(resolve => setTimeout(resolve, backoff));
    }
  }
}

async function navigateAndSettle(page, url, delay) {
  await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 30000 });
  try {
    await page.waitForLoadState('networkidle', { timeout: 5000 });
  } catch {
    // Expected on analytics-heavy pages — continue anyway
  }
  await page.waitForTimeout(delay);
}

export async function captureScreenshots(config) {
  const { url, output, fullPage, delay, browsers: browserNames, devices: deviceNames, uaSpoof, injectEruda } = config;

  if (!url) {
    console.error('❌ Please provide a URL as the first argument');
    console.error('Usage: node capture.mjs <url> [options]');
    process.exit(1);
  }

  const outputDir = path.resolve(output);
  const screenshotsDir = path.join(outputDir, 'screenshots');
  await fs.mkdir(screenshotsDir, { recursive: true });

  const results = [];

  // Standard browser + device combos
  for (const browserName of browserNames) {
    const browserConfig = BROWSER_LAUNCHERS[browserName];
    if (!browserConfig) { console.warn(`⚠️  Unknown browser: ${browserName}, skipping`); continue; }

    const browser = await browserConfig.launcher.launch({ headless: true });

    for (const deviceName of deviceNames) {
      const device = devices[deviceName];
      if (!device) { console.warn(`⚠️  Unknown device: ${deviceName}, skipping`); continue; }

      const platform = getPlatform(device);

      // Skip incompatible combos
      if (platform !== 'desktop') {
        if (browserName === 'webkit' && platform === 'android') continue;
        if (browserName === 'firefox' && device.isMobile) continue;
      }

      const label = `${browserConfig.label} — ${deviceName}`;
      const result = await captureWithRetry(async () => {
        const context = await browser.newContext({
          ...device,
          ...(config.customWidth && { viewport: { width: config.customWidth, height: config.customHeight || device.viewport.height } }),
        });
        const page = await context.newPage();

        if (injectEruda) {
          await page.addScriptTag({ url: 'https://cdn.jsdelivr.net/npm/eruda' });
          await page.evaluate(() => eruda.init());
        }

        await navigateAndSettle(page, url, delay);

        const filename = `${browserName}_${deviceName.replace(/[^a-zA-Z0-9]/g, '_')}.png`;
        const filepath = path.join(screenshotsDir, filename);
        await page.screenshot({ path: filepath, fullPage });
        await context.close();

        return {
          browser: browserConfig.label, browserEngine: browserName,
          device: deviceName, viewport: device.viewport,
          userAgent: device.userAgent, filename, filepath,
          type: 'standard', platform,
        };
      }, label);

      if (result.success) {
        const { success, ...data } = result;
        results.push(data);
      }
    }

    await browser.close();
  }

  // In-app browser UA spoofing
  for (const spoofKey of uaSpoof) {
    const matchingKeys = Object.keys(IN_APP_UA_STRINGS).filter(k => k.startsWith(spoofKey) || k.includes(spoofKey));
    const keysToUse = matchingKeys.length > 0 ? matchingKeys : [spoofKey];

    for (const key of keysToUse) {
      const inApp = IN_APP_UA_STRINGS[key];
      if (!inApp) { console.warn(`⚠️  Unknown in-app browser: ${key}, skipping`); continue; }

      const browserConfig = BROWSER_LAUNCHERS[inApp.engine];
      const device = devices[inApp.device];

      const browser = await browserConfig.launcher.launch({ headless: true });
      const label = inApp.name;
      const result = await captureWithRetry(async () => {
        const context = await browser.newContext({ ...device, userAgent: inApp.ua });
        const page = await context.newPage();
        await navigateAndSettle(page, url, delay);

        const filename = `inapp_${key}.png`;
        const filepath = path.join(screenshotsDir, filename);
        await page.screenshot({ path: filepath, fullPage });
        await context.close();

        return {
          browser: inApp.name, browserEngine: inApp.engine, device: inApp.device,
          viewport: device.viewport, userAgent: inApp.ua, filename, filepath,
          type: 'in-app', platform: inApp.engine === 'webkit' ? 'ios' : 'android',
        };
      }, label);

      if (result.success) {
        const { success, ...data } = result;
        results.push(data);
      }
      await browser.close();
    }
  }

  return results;
}
