 10→const MAX_RETRIES = 3;
 11→const BASE_DELAY_MS = 1000;
 12→
 13→/**
 14→ * Retry a screenshot capture with exponential backoff.
 15→ * Returns { success, ...result } or { success, error }.
 16→ */
 17→async function captureWithRetry(fn, label) {
 18→  for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
 19→    try {
 20→      const result = await fn();
 21→      return { success: true, ...result };
 22→    } catch (err) {
 23→      const isLastAttempt = attempt === MAX_RETRIES;
 24→      if (isLastAttempt) {
 25→        console.error(`  \u274C ${label} — failed after ${MAX_RETRIES} attempts: ${err.message}`);
 26→        return { success: false, error: err.message };
 27→      }
 28→      const backoff = BASE_DELAY_MS * Math.pow(2, attempt - 1);
 29→      console.warn(`  \u26A0\uFE0F  ${label} — attempt ${attempt}/${MAX_RETRIES} failed: ${err.message}. Retrying in ${backoff}ms...`);
 30→      await new Promise(resolve => setTimeout(resolve, backoff));
 31→    }
 32→  }
 33→}
