159→      const browser = await browserConfig.launcher.launch({ headless: true });
160→
161→      const label = inApp.name;
162→      const result = await captureWithRetry(async () => {
163→        const context = await browser.newContext({
164→          ...device,
165→          userAgent: inApp.ua,
166→        });
167→        const page = await context.newPage();
168→
169→        await navigateAndSettle(page, url, delay);
170→
171→        const filename = `inapp_${key}.png`;
172→        const filepath = path.join(screenshotsDir, filename);
173→        await page.screenshot({ path: filepath, fullPage });
174→
175→        await context.close();
176→
177→        return {
178→          browser: inApp.name,
179→          browserEngine: inApp.engine,
180→          device: inApp.device,
181→          viewport: device.viewport,
182→          userAgent: inApp.ua,
