  1→#!/usr/bin/env node
  2→
  3→/**
  4→ * Browser Compatibility Screenshot Comparison Tool
  5→ *
  6→ * Captures screenshots of a target URL across multiple browser engines
  7→ * and device emulations using Playwright, then generates an HTML comparison report.
  8→ *
  9→ * Usage:
 10→ *   node capture.mjs <url> [options]
 11→ *
 12→ * Options:
 13→ *   --output, -o    Output directory (default: ./report)
 14→ *   --width, -w     Custom viewport width
 15→ *   --height, -h    Custom viewport height
 16→ *   --full-page     Capture full page screenshots (default: true)
 17→ *   --delay         Wait ms after page load before capture (default: 2000)
 18→ *   --devices       Comma-separated device list (default: all presets)
 19→ *   --browsers      Comma-separated browser list: chromium,webkit,firefox (default: all)
 20→ *   --inject-eruda  Inject Eruda console for debugging
 21→ *   --ua-spoof      Spoof in-app browser user agents (facebook, instagram, tiktok, etc.)
 22→ *
 23→ * Examples:
 24→ *   node capture.mjs https://example.com
 25→ *   node capture.mjs https://example.com --browsers chromium,webkit --devices "iPhone 15,Pixel 7"
 26→ *   node capture.mjs https://example.com --ua-spoof facebook,instagram,wechat
 27→ */
 28→
 29→import path from 'path';
 30→import fs from 'fs/promises';
 31→import { fileURLToPath } from 'url';
 32→import { DEFAULT_DEVICES } from './lib/browsers.mjs';
 33→import { captureScreenshots } from './lib/capture-engine.mjs';
 34→import { generateReport } from './lib/report-generator.mjs';
 35→
 36→const __dirname = path.dirname(fileURLToPath(import.meta.url));
 37→
 38→// ============================================================
 39→// Defaults
 40→// ============================================================
 41→const DEFAULTS = {
 42→  url: null,
 43→  output: './report',
 44→  fullPage: true,
 45→  delay: 2000,
 46→  devices: DEFAULT_DEVICES,
 47→  browsers: ['chromium', 'webkit', 'firefox'],
 48→  uaSpoof: [],
 49→  injectEruda: false,
 50→  customWidth: null,
 51→  customHeight: null,
 52→};
 53→
 54→// ============================================================
 55→// Parse CLI Arguments
 56→// ============================================================
 57→function parseArgs(args) {
 58→  const parsed = {};
 59→
 60→  let i = 0;
 61→  while (i < args.length) {
 62→    const arg = args[i];
 63→    if (arg === '--output' || arg === '-o') {
 64→      parsed.output = args[++i];
 65→    } else if (arg === '--width' || arg === '-w') {
 66→      parsed.customWidth = parseInt(args[++i]);
 67→    } else if (arg === '--height' || arg === '-h') {
 68→      parsed.customHeight = parseInt(args[++i]);
 69→    } else if (arg === '--full-page') {
 70→      parsed.fullPage = args[++i] !== 'false';
 71→    } else if (arg === '--delay') {
 72→      parsed.delay = parseInt(args[++i]);
 73→    } else if (arg === '--devices') {
 74→      parsed.devices = args[++i].split(',').map(d => d.trim());
 75→    } else if (arg === '--browsers') {
 76→      parsed.browsers = args[++i].split(',').map(b => b.trim().toLowerCase());
 77→    } else if (arg === '--ua-spoof') {
 78→      parsed.uaSpoof = args[++i].split(',').map(u => u.trim().toLowerCase());
 79→    } else if (arg === '--inject-eruda') {
 80→      parsed.injectEruda = true;
 81→    } else if (!arg.startsWith('-')) {
 82→      parsed.url = arg;
 83→    }
 84→    i++;
 85→  }
 86→
 87→  return parsed;
 88→}
 89→
 90→// ============================================================
 91→// Load .browsercompare.json config
 92→// ============================================================
 93→async function loadConfigFile() {
 94→  const configPath = path.resolve(process.cwd(), '.browsercompare.json');
 95→  try {
 96→    const raw = await fs.readFile(configPath, 'utf-8');
 97→    const config = JSON.parse(raw);
 98→    console.log(`\uD83D\uDCC4 Loaded config from ${configPath}`);
 99→    return config;
100→  } catch {
101→    return {};
102→  }
103→}
104→
105→// ============================================================
106→// Main
107→// ============================================================
108→const fileConfig = await loadConfigFile();
109→const cliArgs = parseArgs(process.argv.slice(2));
110→
111→// Merge order: defaults < config file < CLI args
112→const config = { ...DEFAULTS, ...fileConfig, ...cliArgs };
113→
114→const results = await captureScreenshots(config);
115→await generateReport(results, config, __dirname);
