421→<script>
422→// ============================================================
423→// Data & State
424→// ============================================================
425→const metadata = __METADATA__;
426→let currentFilter = 'all';
427→let currentPlatform = 'all';
428→let currentView = 'grid';
429→let diffSelections = [];
430→
431→document.getElementById('total-count').textContent = metadata.results.length;
432→
433→// ============================================================
434→// Render
435→// ============================================================
436→function getFilteredResults() {
437→  return metadata.results.filter(r => {
438→    const engineMatch = currentFilter === 'all'
439→      || (currentFilter === 'in-app' && r.type === 'in-app')
440→      || (r.browserEngine === currentFilter && r.type !== 'in-app');
441→    const platformMatch = currentPlatform === 'all'
442→      || r.platform === currentPlatform;
443→    return engineMatch && platformMatch;
444→  });
445→}
446→
447→function renderStats() {
448→  const results = metadata.results;
449→  const engines = [...new Set(results.map(r => r.browserEngine))];
450→  const devices = [...new Set(results.map(r => r.device))];
451→  const inAppCount = results.filter(r => r.type === 'in-app').length;
452→
453→  document.getElementById('stats').innerHTML = `
454→    <div class="stat-chip">
455→      <span class="stat-number">${results.length}</span>
456→      <span class="stat-label">Total<br>Screenshots</span>
457→    </div>
458→    <div class="stat-chip">
459→      <span class="stat-number">${engines.length}</span>
460→      <span class="stat-label">Browser<br>Engines</span>
461→    </div>
462→    <div class="stat-chip">
463→      <span class="stat-number">${devices.length}</span>
464→      <span class="stat-label">Device<br>Profiles</span>
465→    </div>
466→    <div class="stat-chip">
467→      <span class="stat-number">${inAppCount}</span>
468→      <span class="stat-label">In-App<br>Browsers</span>
469→    </div>
470→  `;
471→}
472→
473→function createCard(result, index) {
474→  const engineTag = result.type === 'in-app' ? 'inapp' : result.browserEngine;
475→  const platformTag = result.platform;
476→  const isDiffMode = currentView === 'diff';
477→  const isSelected = diffSelections.includes(index);
478→
479→  return `
480→    <div class="card ${isSelected ? 'diff-selected' : ''}"
481→         data-index="${index}"
482→         ${isDiffMode ? `onclick="toggleDiffSelect(${index})"` : ''}>
483→      <div class="card-header">
484→        <div>
485→          <div class="card-title">${result.browser}</div>
486→          <div class="card-subtitle">${result.device}</div>
487→        </div>
488→        <div class="card-tags">
489→          <span class="tag tag-${engineTag}">${result.browserEngine}</span>
490→          <span class="tag tag-${platformTag}">${platformTag}</span>
491→        </div>
492→      </div>
493→      <div class="card-image-container" ${!isDiffMode ? `onclick="openLightbox('screenshots/${result.filename}', '${result.browser} — ${result.device}')"` : ''}>
494→        <img src="screenshots/${result.filename}" alt="${result.browser} ${result.device}" loading="lazy">
495→      </div>
496→      <div class="card-footer">
497→        <span>${result.viewport.width} × ${result.viewport.height}</span>
498→        <span>${result.type === 'in-app' ? '📲 In-App WebView' : '🌐 Native Browser'}</span>
499→      </div>
500→    </div>
501→  `;
502→}
503→
504→function render() {
505→  const container = document.getElementById('cards-container');
506→  const filtered = getFilteredResults();
507→
508→  container.className = currentView === 'side-by-side' ? 'side-by-side-view'
509→    : currentView === 'diff' ? 'diff-view'
510→    : 'grid-view';
511→
512→  if (filtered.length === 0) {
513→    container.innerHTML = `
514→      <div class="empty" style="grid-column: 1/-1;">
515→        <div class="empty-icon">🔍</div>
516→        <p>No screenshots match your filters</p>
517→      </div>`;
518→    return;
519→  }
520→
521→  container.innerHTML = filtered.map((r, i) => createCard(r, metadata.results.indexOf(r))).join('');
522→}
