  8→/**
  9→ * Generate an HTML comparison report from capture results.
 10→ * @param {Array} results - Screenshot capture results
 11→ * @param {Object} config - Capture configuration
 12→ * @param {string} templateDir - Directory containing report-template.html
 13→ */
 14→export async function generateReport(results, config, templateDir) {
 15→  const outputDir = path.resolve(config.output);
 16→
 17→  const metadata = {
 18→    url: config.url,
 19→    capturedAt: new Date().toISOString(),
 20→    results: results.map(r => ({
 21→      ...r,
 22→      filepath: undefined,
 23→    })),
 24→  };
 25→
 26→  await fs.writeFile(
 27→    path.join(outputDir, 'metadata.json'),
 28→    JSON.stringify(metadata, null, 2)
 29→  );
 30→
 31→  const templatePath = path.join(templateDir, 'report-template.html');
 32→  let template;
 33→  try {
 34→    template = await fs.readFile(templatePath, 'utf-8');
 35→  } catch {
 36→    template = generateDefaultTemplate();
 37→  }
 38→
 39→  const html = template
 40→    .replace('__METADATA__', JSON.stringify(metadata))
 41→    .replace('__URL__', config.url)
 42→    .replace('__DATE__', new Date().toLocaleString());
 43→
 44→  await fs.writeFile(path.join(outputDir, 'index.html'), html);
 45→
 46→  console.log(`\n\u2705 Report generated: ${path.join(outputDir, 'index.html')}`);
 47→  console.log(`\uD83D\uDCF8 ${results.length} screenshots captured`);
 48→
 49→  return path.join(outputDir, 'index.html');
 50→}
