    url: config.url,
    capturedAt: new Date().toISOString(),
    results: results.map(r => ({ ...r, filepath: undefined })),
  };

  await fs.writeFile(path.join(outputDir, 'metadata.json'), JSON.stringify(metadata, null, 2));

  const templatePath = path.join(templateDir, 'report-template.html');
