372→    <h1>Browser Compatibility Report</h1>
373→  </div>
374→  <div class="header-meta">
375→    <div class="header-meta-item">
376→      URL: <code id="target-url">__URL__</code>
377→    </div>
378→    <div class="header-meta-item">
379→      Captured: <code id="capture-date">__DATE__</code>
380→    </div>
381→    <div class="header-meta-item">
382→      Screenshots: <code id="total-count">0</code>
383→    </div>
384→  </div>
385→</div>
