473→function createCard(result, index) {
474→  const engineTag = result.type === 'in-app' ? 'inapp' : result.browserEngine;
475→  const platformTag = result.platform;
476→  const isDiffMode = currentView === 'diff';
477→  const isSelected = diffSelections.includes(index);
