524→// ============================================================
525→// Filters
526→// ============================================================
527→document.getElementById('engine-filters').addEventListener('click', e => {
528→  if (!e.target.matches('.filter-btn')) return;
529→  document.querySelectorAll('#engine-filters .filter-btn').forEach(b => b.classList.remove('active', 'active-chromium', 'active-webkit', 'active-firefox', 'active-inapp'));
530→  const filter = e.target.dataset.filter;
531→  currentFilter = filter;
532→  e.target.classList.add('active');
533→  if (filter !== 'all') e.target.classList.add('active-' + (filter === 'in-app' ? 'inapp' : filter));
534→  render();
535→});
536→
537→document.getElementById('platform-filters').addEventListener('click', e => {
538→  if (!e.target.matches('.filter-btn')) return;
539→  document.querySelectorAll('#platform-filters .filter-btn').forEach(b => b.classList.remove('active'));
540→  currentPlatform = e.target.dataset.platform;
541→  e.target.classList.add('active');
542→  render();
543→});
544→
545→document.querySelector('.view-toggle').addEventListener('click', e => {
546→  if (!e.target.matches('.filter-btn')) return;
547→  document.querySelectorAll('.view-toggle .filter-btn').forEach(b => b.classList.remove('active'));
548→  currentView = e.target.dataset.view;
549→  e.target.classList.add('active');
550→  diffSelections = [];
551→  render();
552→});
553→
554→// ============================================================
555→// Diff Mode
556→// ============================================================
557→function toggleDiffSelect(index) {
558→  const pos = diffSelections.indexOf(index);
559→  if (pos >= 0) {
560→    diffSelections.splice(pos, 1);
561→  } else if (diffSelections.length < 2) {
562→    diffSelections.push(index);
563→  }
564→  render();
565→}
566→
567→// ============================================================
568→// Lightbox
569→// ============================================================
