  1→/**
  2→ * Core capture logic with retry support
  3→ */
  4→
  5→import { devices } from 'playwright';
  6→import path from 'path';
  7→import fs from 'fs/promises';
  8→import { IN_APP_UA_STRINGS, BROWSER_LAUNCHERS, getPlatform } from './browsers.mjs';
  9→
 10→const MAX_RETRIES = 3;
 11→const BASE_DELAY_MS = 1000;
 12→
 13→/**
 14→ * Retry a screenshot capture with exponential backoff.
 15→ * Returns { success, ...result } or { success, error }.
 16→ */
 17→async function captureWithRetry(fn, label) {
 18→  for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
 19→    try {
 20→      const result = await fn();
 21→      return { success: true, ...result };
 22→    } catch (err) {
 23→      const isLastAttempt = attempt === MAX_RETRIES;
 24→      if (isLastAttempt) {
 25→        console.error(`  \u274C ${label} — failed after ${MAX_RETRIES} attempts: ${err.message}`);
 26→        return { success: false, error: err.message };
 27→      }
 28→      const backoff = BASE_DELAY_MS * Math.pow(2, attempt - 1);
 29→      console.warn(`  \u26A0\uFE0F  ${label} — attempt ${attempt}/${MAX_RETRIES} failed: ${err.message}. Retrying in ${backoff}ms...`);
 30→      await new Promise(resolve => setTimeout(resolve, backoff));
 31→    }
 32→  }
 33→}
 34→
 35→/**
 36→ * Navigate to a URL and wait for the page to be visually ready.
 37→ * Uses a two-phase strategy:
 38→ *   1. Wait for 'domcontentloaded' (reliable, works on all pages)
 39→ *   2. Optionally wait for 'networkidle' with a short timeout (best-effort)
 40→ */
 41→async function navigateAndSettle(page, url, delay) {
 42→  await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 30000 });
 43→
 44→  try {
 45→    await page.waitForLoadState('networkidle', { timeout: 5000 });
 46→  } catch {
 47→    // Expected on analytics-heavy pages (Shopify, etc.) — continue anyway
 48→  }
 49→
 50→  await page.waitForTimeout(delay);
 51→}
 52→
 53→/**
 54→ * Capture screenshots across browser engines and device emulations.
 55→ */
 56→export async function captureScreenshots(config) {
 57→  const { url, output, fullPage, delay, browsers: browserNames, devices: deviceNames, uaSpoof, injectEruda } = config;
 58→
 59→  if (!url) {
 60→    console.error('\u274C Please provide a URL as the first argument');
 61→    console.error('Usage: node capture.mjs <url> [options]');
 62→    process.exit(1);
 63→  }
 64→
 65→  const outputDir = path.resolve(output);
 66→  const screenshotsDir = path.join(outputDir, 'screenshots');
 67→  await fs.mkdir(screenshotsDir, { recursive: true });
 68→
 69→  const results = [];
 70→
 71→  // 1. Standard browser + device combos
 72→  for (const browserName of browserNames) {
 73→    const browserConfig = BROWSER_LAUNCHERS[browserName];
 74→    if (!browserConfig) {
 75→      console.warn(`\u26A0\uFE0F  Unknown browser: ${browserName}, skipping`);
 76→      continue;
 77→    }
 78→
 79→    console.log(`\n\uD83D\uDE80 Launching ${browserConfig.label}...`);
 80→    const browser = await browserConfig.launcher.launch({ headless: true });
 81→
 82→    for (const deviceName of deviceNames) {
 83→      const device = devices[deviceName];
 84→      if (!device) {
 85→        console.warn(`\u26A0\uFE0F  Unknown device: ${deviceName}, skipping`);
 86→        continue;
 87→      }
 88→
 89→      const platform = getPlatform(device);
 90→
 91→      // Skip incompatible combos (desktop devices work with all engines)
 92→      if (platform !== 'desktop') {
 93→        if (browserName === 'webkit' && platform === 'android') continue;
 94→        if (browserName === 'firefox' && device.isMobile) continue;
 95→      }
 96→
 97→      const label = `${browserConfig.label} \u2014 ${deviceName}`;
 98→      console.log(`  \uD83D\uDCF1 ${label}`);
 99→
100→      const result = await captureWithRetry(async () => {
101→        const context = await browser.newContext({
102→          ...device,
103→          ...(config.customWidth && { viewport: { width: config.customWidth, height: config.customHeight || device.viewport.height } }),
104→        });
105→        const page = await context.newPage();
106→
107→        if (injectEruda) {
108→          await page.addScriptTag({ url: 'https://cdn.jsdelivr.net/npm/eruda' });
109→          await page.evaluate(() => eruda.init());
110→        }
111→
112→        await navigateAndSettle(page, url, delay);
113→
114→        const filename = `${browserName}_${deviceName.replace(/[^a-zA-Z0-9]/g, '_')}.png`;
115→        const filepath = path.join(screenshotsDir, filename);
116→        await page.screenshot({ path: filepath, fullPage });
117→
118→        await context.close();
119→
120→        return {
121→          browser: browserConfig.label,
122→          browserEngine: browserName,
123→          device: deviceName,
124→          viewport: device.viewport,
125→          userAgent: device.userAgent,
126→          filename,
127→          filepath,
128→          type: 'standard',
129→          platform,
