135→        results.push(data);
136→      }
137→    }
138→
139→    await browser.close();
140→  }
141→
142→  // 2. In-app browser UA spoofing
143→  for (const spoofKey of uaSpoof) {
144→    const matchingKeys = Object.keys(IN_APP_UA_STRINGS).filter(k => k.startsWith(spoofKey) || k.includes(spoofKey));
145→    const keysToUse = matchingKeys.length > 0 ? matchingKeys : [spoofKey];
146→
147→    for (const key of keysToUse) {
148→      const inApp = IN_APP_UA_STRINGS[key];
149→      if (!inApp) {
150→        console.warn(`\u26A0\uFE0F  Unknown in-app browser: ${key}, skipping`);
151→        continue;
152→      }
153→
154→      const browserConfig = BROWSER_LAUNCHERS[inApp.engine];
155→      const device = devices[inApp.device];
156→
157→      console.log(`\n\uD83D\uDCF2 ${inApp.name} (${browserConfig.label} engine)`);
158→
159→      const browser = await browserConfig.launcher.launch({ headless: true });
160→
161→      const label = inApp.name;
162→      const result = await captureWithRetry(async () => {
163→        const context = await browser.newContext({
164→          ...device,
165→          userAgent: inApp.ua,
166→        });
167→        const page = await context.newPage();
168→
169→        await navigateAndSettle(page, url, delay);
170→
171→        const filename = `inapp_${key}.png`;
172→        const filepath = path.join(screenshotsDir, filename);
173→        await page.screenshot({ path: filepath, fullPage });
